import React, { useState, useEffect } from "react";
import axios from "axios";
import Swal from "sweetalert2";

export default function EditProfile({ closeModal }) {
  const [user, setUser] = useState(null);
  const [name, setName] = useState("");
  const [username, setUsername] = useState("");
  const [imageFile, setImageFile] = useState(null);

  useEffect(() => {
    const raw = localStorage.getItem("user");
    const stored = raw ? JSON.parse(raw) : null;

    if (!stored?.email) return;

    axios
      .get(`http://localhost:8086/user/profile?email=${stored.email}`)
      .then((res) => {
        setUser(res.data);
        setName(res.data.name);
        setUsername(res.data.username);
      })
      .catch((err) => console.log(err));
  }, []);

  const handleUpdate = async () => {
    try {
      const formData = new FormData();
      formData.append("name", name);
      formData.append("username", username);

      if (imageFile) {
        formData.append("image", imageFile);
      }

      await axios.put(
        `http://localhost:8086/user/update/${user.id}`,
        formData,
        {
          headers: { "Content-Type": "multipart/form-data" },
        }
      );

      Swal.fire("Success", "Profile updated successfully", "success");

      // update localStorage (optional)
      const updatedUser = { ...user, name, username };
      localStorage.setItem("user", JSON.stringify(updatedUser));

      closeModal(); // close modal after success
      window.location.reload();
    } catch (err) {
      console.log(err);
      Swal.fire("Error", "Update failed", "error");
    }
  };

  if (!user) return null;

  return (
    <div className="fixed inset-0 bg-black/40 backdrop-blur-sm flex items-center justify-center z-50">

      <div className="bg-white w-full max-w-md rounded-2xl shadow-2xl p-6 relative">

        {/* CLOSE BUTTON */}
        <button
          onClick={closeModal}
          className="absolute top-3 right-3 text-gray-500 hover:text-red-500 text-xl"
        >
          ✕
        </button>

        <h2 className="text-xl font-bold mb-4 text-gray-800">
          Edit Profile
        </h2>

        {/* NAME */}
        <input
          type="text"
          value={name}
          onChange={(e) => setName(e.target.value)}
          placeholder="Name"
          className="w-full mb-3 p-2 border rounded-lg"
        />

        {/* USERNAME */}
        <input
          type="text"
          value={username}
          onChange={(e) => setUsername(e.target.value)}
          placeholder="Username"
          className="w-full mb-3 p-2 border rounded-lg"
        />

        {/* IMAGE UPLOAD */}
        <input
          type="file"
          onChange={(e) => setImageFile(e.target.files[0])}
          className="w-full mb-4"
        />

        {/* BUTTONS */}
        <div className="flex gap-3">
          <button
            onClick={handleUpdate}
            className="flex-1 bg-indigo-600 text-white py-2 rounded-lg hover:bg-indigo-700"
          >
            Save
          </button>

          <button
            onClick={closeModal}
            className="flex-1 bg-gray-300 text-gray-800 py-2 rounded-lg hover:bg-gray-400"
          >
            Cancel
          </button>
        </div>

      </div>
    </div>
  );
}
